<style lang="scss">
  footer {
    position: relative;
    z-index: 8;
    color: var(--foreground-inverse);
    background-color: var(--background-inverse);

    :global(.-carrieres) & {
      color: $green-dark;
      background-color: $white;
    }

    :global(.-contact) & {
      color: var(--foreground);
      background-color: var(--background);
    }

    :global(.-a-propos) &,
    :global(.-articles) & {
      color: var(--foreground);
      background-color: $green-light;
    }

    display: flex;
    border-top: 1px solid;

    @media (max-width: $mobile) {
      position: relative;
      flex-wrap: wrap;

      .logo {
        position: absolute;
        left: $base * 2;
        bottom: $base;
        z-index: 2;
      }
    }

    nav {
      display: flex;
      padding: $gap;
      gap: $gap * 3;

      a {

        &:hover,
        &:focus {
          text-decoration: none;
          color: $white;
        }
      }

      &:first-child {
        margin-left: $base;
        border-left: 1px solid;

        @media (max-width: $mobile) {
          margin: 0 ($mobile_base * 0.75);
          border-right: 1px solid;
        }
      }

      &:last-child {
        margin-right: $base;
        border-right: 1px solid;
        justify-content: flex-end;
        flex: 1;

        @media (max-width: $mobile) {
          margin: 0 ($mobile_base * 0.75);
          border-left: 1px solid;
        }
      }

      div {
        display: flex;
        flex-direction: column;
      }

      &:last-of-type {
        svg {
          height: 120px;
        }

        @media (max-width: $mobile) {
          align-items: flex-end;

          a {
            width: auto;

            &:first-child {
              order: 99;
            }
          }
          svg {
            height: 80px;
          }
        }
      }

      @media (max-width: $mobile) {
        width: 100%;
        flex-wrap: wrap;
        gap: $gap;
        // column-gap: 0;
        padding: $base;

        a {
          width: 50%;

          // &:last-of-type {
          //   order: 99;
          // }
        }
      }
    }
  }
</style>